// Shape the incoming message (chat text, or a transcribed voice note)
// into Gloo chat messages. Safety note: the Resonate engine's crisis gate
// should be called FIRST in production — see integrations/n8n/README.md.
const body = $input.first().json.body || {};
const text = (body.text || '').trim();
const history = Array.isArray(body.history) ? body.history : [];
const messages = [
  { role: 'system', content: 'You are Scripture Guide — warm, reverent, honest. You know the Scriptures deeply and discuss them plainly: context, meaning, hard questions, differing views. Quote verses only when you can cite book/chapter/verse; never invent wording. If someone signals crisis, respond with care and human help lines, never a verse.' },
  ...history.map((h) => ({ role: 'user', content: String(h) })),
  { role: 'user', content: text },
];
return [{ json: { messages, max_tokens: 600, auto_routing: true } }];
